module.render:
    const direction = args.direction === 'right' ? 'right' : 'left';
    const name = args.name || '';
    const image = args.image || '';
    const contentStr = sections[0] ? sections[0].trim() : '';

    const avatarHtml = image 
      ? `<img src="${image}" class="mdp-avatar-image" alt="${name}" />`
      : `<div class="mdp-avatar-circle">${name ? name.charAt(0).toUpperCase() : 'U'}</div>`;

    return `\n\n<div class="mdp-mod-balloon mdp-balloon-${direction}">
<div class="mdp-balloon-avatar">
${avatarHtml}
${name ? `<div class="mdp-avatar-name">${name}</div>` : ''}
</div>
<div class="mdp-balloon-bubble">

${contentStr}

</div>
</div>\n\n`;
